function switchToEnglish(){localStorage.setItem("language","en"),window.location.href="/en/"}function switchToRussian(){localStorage.setItem("language","ru"),window.location.href="/"}document.addEventListener("DOMContentLoaded",()=>{let e=()=>{let e=document.querySelector(".follow-cursor");window.addEventListener("mousemove",t=>{let o=t.target;o&&(o.closest("a")?e.classList.add("follow-cursor_active"):e.classList.remove("follow-cursor_active"),e.style.left=t.pageX+"px",e.style.top=t.pageY+"px")})};e()});